sql:
SELECT deaths, SQRT(deaths) AS sqrt_deaths
FROM deaths
WHERE deaths > 100;

SELECT * 
FROM counties
ORDER BY population DESC;

SELECT SUM(pos_cases) AS total_state_cases, SUM(deaths) AS total_state_deaths
FROM state_data
WHERE date = '2021-03-27';

