sql:
SELECT number_of_outbreaks 
FROM outbreaks
WHERE outbreak_id = 1 AND dataset_id = 1 AND date = '2021-03-27';

SELECT COUNT(*) 
FROM outbreaks 
WHERE new_outbreaks > 500;

SELECT cumulative_deaths
FROM county_deaths_over_time
WHERE date = '2021-03-27' AND dataset_id = 1;

SELECT county_name, population
FROM counties
ORDER BY population DESC;
